kubectl exec -n mongodb mongodb-replica-0 -- mongo --quiet --eval "
db = db.getSiblingDB('admin');
db.createUser({
  user: 'admin',
  pwd: 'admin123password',
  roles: [{role: 'root', db: 'admin'}]
});
print('User created');
" 2>&1

